import 'dart:convert';

import 'package:google_maps_flutter/google_maps_flutter.dart';

class BuildingPolygon {
  final String code;
  final String name;
  final List<LatLng> points;

  const BuildingPolygon({
    required this.code,
    required this.name,
    required this.points,
  });

  /// Calculate the center point of the building polygon
  LatLng get center {
    if (points.isEmpty) {
      return const LatLng(0, 0);
    }

    double latSum = 0;
    double lngSum = 0;

    for (final point in points) {
      latSum += point.latitude;
      lngSum += point.longitude;
    }

    return LatLng(latSum / points.length, lngSum / points.length);
  }

  /// Check if a point is inside this building polygon
  bool containsPoint(LatLng point) {
    if (points.length < 3) return false;

    bool inside = false;
    int j = points.length - 1;

    for (int i = 0; i < points.length; i++) {
      if (((points[i].latitude > point.latitude) !=
              (points[j].latitude > point.latitude)) &&
          (point.longitude <
              (points[j].longitude - points[i].longitude) *
                      (point.latitude - points[i].latitude) /
                      (points[j].latitude - points[i].latitude) +
                  points[i].longitude)) {
        inside = !inside;
      }
      j = i;
    }

    return inside;
  }
}

final List<BuildingPolygon> buildingPolygons =
    LineSplitter.split(_buildingPolygonData)
        .where((line) => line.isNotEmpty)
        .map(_parseBuildingPolygonRow)
        .toList(growable: false);

BuildingPolygon _parseBuildingPolygonRow(String row) {
  final firstSeparator = row.indexOf('|');
  final secondSeparator = row.indexOf('|', firstSeparator + 1);

  if (firstSeparator <= 0 || secondSeparator <= firstSeparator + 1) {
    throw FormatException('Invalid building polygon row: $row');
  }

  final code = row.substring(0, firstSeparator);
  final name = row.substring(firstSeparator + 1, secondSeparator);
  final points = row
      .substring(secondSeparator + 1)
      .split(';')
      .where((pair) => pair.isNotEmpty)
      .map(_parseLatLngPair)
      .toList(growable: false);

  return BuildingPolygon(code: code, name: name, points: points);
}

LatLng _parseLatLngPair(String pair) {
  final separator = pair.indexOf(',');
  if (separator <= 0 || separator >= pair.length - 1) {
    throw FormatException('Invalid LatLng pair: $pair');
  }

  final latitude = double.parse(pair.substring(0, separator));
  final longitude = double.parse(pair.substring(separator + 1));
  return LatLng(latitude, longitude);
}

